export const buildAuth = (db) => betterAuth({
    database: prismaAdapter(db),
    databaseHooks: {
        user: {
            create: async (user) => {
                const created = await db.user.create({ data: user });
                await ensureOrgMembership(created, { db });
                await ensureBillingProvisioning(created, { db });
                await analytics.capture('user_signed_up', { userId: created.id });
                await fireSignupWebhook(created);
                return created;
            },
        },
    },
});
